ins = upd = 0
for num, en, kn in skills:
    key = f"keyskill.{num}"
    ex = db.execute(text("SELECT id FROM explanation_translations WHERE explanation_key=:k AND locale='kn' AND content_version='v1'"), {"k": key}).fetchone()
    if ex:
        db.execute(text("UPDATE explanation_translations SET text=:t, updated_at=:ts WHERE explanation_key=:k AND locale='kn' AND content_version='v1'"), {"t": kn, "ts": now, "k": key})
        upd += 1
    else:
        db.execute(text("INSERT INTO explanation_translations (content_version, locale, explanation_key, text, is_active, updated_at) VALUES ('v1','kn',:k,:t,true,:ts)"), {"k": key, "t": kn, "ts": now})
        ins += 1
db.commit()
print(f"  Done: {ins} inserted, {upd} updated")

